@Module
@InstallIn(SingletonComponent::class)
abstract class AnalyticsModule {
    @Binds @IntoSet
    abstract fun bindFirebase(impl: FirebaseTracker): AnalyticsTracker

    @Binds @IntoSet
    abstract fun bindMixpanel(impl: MixpanelTracker): AnalyticsTracker
}

class AnalyticsManager @Inject constructor(
    private val trackers: Set<@JvmSuppressWildcards AnalyticsTracker>
) {
    fun track(event: String, params: Map<String, String> = emptyMap()) {
        trackers.forEach { it.track(event, params) }
    }
}

